import React, { useEffect, useMemo, useState } from 'react';
import QRCode from 'qrcode';
import { toAbsoluteImageUrl } from '../../utils/imageUrl';

const formatCurrency = (value) =>
  new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(Number(value || 0));

const CUSTOMER_DISPLAY_STATE_KEY = 'khmart_customer_display_state';

const getInitialDisplayState = () => ({
  cart: [],
  paymentMethod: 'Cash',
  subtotal: 0,
  discountAmount: 0,
  total: 0,
  amountTendered: 0,
  changeAmount: 0,
  updatedAt: null,
});

const readDisplayState = () => {
  try {
    const raw = localStorage.getItem(CUSTOMER_DISPLAY_STATE_KEY);
    if (!raw) {
      return getInitialDisplayState();
    }

    const parsed = JSON.parse(raw);
    return {
      ...getInitialDisplayState(),
      ...parsed,
      cart: Array.isArray(parsed?.cart) ? parsed.cart : [],
    };
  } catch {
    return getInitialDisplayState();
  }
};

const CustomerDisplay = () => {
  const [displayState, setDisplayState] = useState(() => readDisplayState());
  const [now, setNow] = useState(new Date());
  const [qrDataUrl, setQrDataUrl] = useState('');

  const syncFromStorage = () => {
    setDisplayState(readDisplayState());
  };

  useEffect(() => {
    const clockId = setInterval(() => setNow(new Date()), 1000);

    const onStorage = (event) => {
      if (event.key === CUSTOMER_DISPLAY_STATE_KEY) {
        syncFromStorage();
      }
    };

    const onCustomUpdate = () => syncFromStorage();

    window.addEventListener('storage', onStorage);
    window.addEventListener('khmart-customer-display-updated', onCustomUpdate);

    return () => {
      clearInterval(clockId);
      window.removeEventListener('storage', onStorage);
      window.removeEventListener('khmart-customer-display-updated', onCustomUpdate);
    };
  }, []);

  const cart = useMemo(() => (Array.isArray(displayState.cart) ? displayState.cart : []), [displayState.cart]);
  const itemCount = useMemo(() => cart.reduce((sum, item) => sum + (Number(item.qty) || 0), 0), [cart]);
  const subtotal = Number(displayState.subtotal || 0);
  const discountAmount = Number(displayState.discountAmount || 0);
  const total = Number(displayState.total || 0);
  const amountTendered = Number(displayState.amountTendered || 0);
  const changeAmount = Number(displayState.changeAmount || 0);
  const paymentMethod = String(displayState.paymentMethod || 'Cash');

  const qrText = useMemo(() => {
    if (paymentMethod !== 'ABA' || total <= 0) {
      return '';
    }

    return [
      'KH MART POS',
      `PAYMENT: ${paymentMethod}`,
      `AMOUNT: ${formatCurrency(total)}`,
      `TIME: ${now.toLocaleString('en-US')}`,
    ].join('\n');
  }, [now, paymentMethod, total]);

  useEffect(() => {
    let mounted = true;

    const generateQr = async () => {
      if (!qrText) {
        setQrDataUrl('');
        return;
      }

      try {
        const dataUrl = await QRCode.toDataURL(qrText, {
          width: 360,
          margin: 1,
          color: {
            dark: '#082f49',
            light: '#ffffff',
          },
        });

        if (mounted) {
          setQrDataUrl(dataUrl);
        }
      } catch {
        if (mounted) {
          setQrDataUrl('');
        }
      }
    };

    generateQr();

    return () => {
      mounted = false;
    };
  }, [qrText]);

  return (
    <div className="min-h-screen text-white bg-[radial-gradient(circle_at_8%_8%,rgba(59,130,246,0.24),transparent_36%),radial-gradient(circle_at_95%_0%,rgba(16,185,129,0.24),transparent_30%),linear-gradient(130deg,#0f172a_0%,#111827_50%,#052e2b_100%)]">
      <header className="sticky top-0 z-20 px-6 py-5 border-b border-white/10 bg-slate-950/45 backdrop-blur-xl">
        <div className="flex items-center justify-between mx-auto max-w-screen-2xl">
          <div>
            <p className="text-[11px] font-bold uppercase tracking-[0.24em] text-emerald-300">Live POS Screen</p>
            <h1 className="mt-1 text-2xl font-black tracking-tight sm:text-3xl">KH Mart Customer View</h1>
            <p className="text-sm text-emerald-100/85">Scanned products update in realtime</p>
          </div>
          <div className="text-right">
            <p className="text-xl font-black tabular-nums">{now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}</p>
            <p className="text-sm text-emerald-200/90">{now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>
          </div>
        </div>
      </header>

      <main className="px-6 py-6 mx-auto max-w-screen-2xl">
        <div className="grid gap-5 lg:grid-cols-[minmax(0,1fr)_360px]">
          <section className="overflow-hidden rounded-2xl border border-white/15 bg-white/[0.08] shadow-[0_12px_36px_rgba(2,6,23,0.35)]">
            <div className="flex items-center justify-between border-b border-white/10 px-4 py-3">
              <h2 className="text-lg font-black tracking-tight text-white">Current Order</h2>
              <span className="rounded-full border border-emerald-300/30 bg-emerald-400/10 px-3 py-1 text-xs font-bold text-emerald-100">
                {itemCount} item(s)
              </span>
            </div>

            <div className="grid grid-cols-[minmax(0,1fr)_80px_100px_120px] gap-3 border-b border-white/10 px-4 py-3 text-xs font-bold uppercase tracking-[0.12em] text-emerald-200/80">
              <span>Product</span>
              <span className="text-center">Qty</span>
              <span className="text-right">Price</span>
              <span className="text-right">Total</span>
            </div>

            <div className="max-h-[68vh] overflow-auto px-3 py-2">
              {cart.length === 0 ? (
                <div className="flex min-h-[300px] items-center justify-center rounded-xl border border-dashed border-white/15 bg-slate-950/20 px-6 text-center">
                  <div>
                    <h3 className="text-2xl font-black text-white">Waiting for scanned products...</h3>
                    <p className="mt-2 text-emerald-100/85">Items scanned in POS will appear here in realtime.</p>
                  </div>
                </div>
              ) : (
                <div className="space-y-2">
                  {cart.map((item, index) => (
                    <div
                      key={`${item.productId || index}-${index}`}
                      className="grid grid-cols-[54px_minmax(0,1fr)_80px_100px_120px] items-center gap-3 rounded-xl border border-white/10 bg-slate-950/20 px-2 py-2"
                    >
                      <div className="h-12 w-12 overflow-hidden rounded-lg bg-black/25">
                        {item.imageUrl ? (
                          <img
                            src={toAbsoluteImageUrl(item.imageUrl)}
                            alt={item.productName || 'Product'}
                            className="h-full w-full object-cover"
                          />
                        ) : (
                          <div className="flex h-full w-full items-center justify-center text-[10px] text-slate-300">No Img</div>
                        )}
                      </div>
                      <div className="min-w-0">
                        <p className="truncate text-base font-black text-white">{item.productName || 'Unnamed Product'}</p>
                        <p className="text-xs text-emerald-100/80">Realtime POS item</p>
                      </div>
                      <div className="text-center text-base font-black text-emerald-200">x{Number(item.qty) || 0}</div>
                      <div className="text-right text-base font-bold text-white">{formatCurrency(item.price)}</div>
                      <div className="text-right text-lg font-black text-emerald-200">{formatCurrency(item.lineTotal)}</div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </section>

          <aside className="space-y-4">
            <div className="rounded-2xl border border-white/15 bg-white/[0.08] p-4 shadow-[0_12px_36px_rgba(2,6,23,0.35)]">
              <div className="flex items-center justify-between">
                <p className="text-xs font-bold uppercase tracking-[0.12em] text-emerald-200">Payment Method</p>
                <span className="rounded-full border border-sky-300/30 bg-sky-400/10 px-2.5 py-1 text-xs font-bold text-sky-100">
                  {paymentMethod}
                </span>
              </div>
            </div>

            <aside className="space-y-4">
              <div className="rounded-2xl border border-white/15 bg-white/[0.08] p-4 shadow-[0_12px_36px_rgba(2,6,23,0.35)]">
                <div className="space-y-2 text-sm">
                  <div className="flex items-center justify-between text-emerald-100/80">
                    <span>Subtotal</span>
                    <span className="font-bold text-white">{formatCurrency(subtotal)}</span>
                  </div>
                  <div className="flex items-center justify-between text-emerald-100/80">
                    <span>Discount</span>
                    <span className="font-bold text-emerald-200">- {formatCurrency(discountAmount)}</span>
                  </div>
                  <div className="flex items-center justify-between border-t border-white/10 pt-2">
                    <span className="text-lg font-black">Grand Total</span>
                    <span className="text-3xl font-black text-emerald-200">{formatCurrency(total)}</span>
                  </div>
                </div>
              </div>

              {paymentMethod === 'ABA' && total > 0 ? (
                <div className="rounded-2xl border border-sky-200/40 bg-sky-500/10 p-4 text-center shadow-[0_12px_36px_rgba(2,6,23,0.35)]">
                  <p className="text-xs font-bold uppercase tracking-[0.12em] text-sky-200">Scan to Pay</p>
                  <p className="mt-1 text-lg font-black text-white">ABA QR Payment</p>
                  <div className="mx-auto mt-4 w-full max-w-[260px] overflow-hidden rounded-xl border border-white/20 bg-white p-3">
                    {qrDataUrl ? (
                      <img src={qrDataUrl} alt="ABA QR" className="h-auto w-full" />
                    ) : (
                      <div className="py-10 text-sm text-slate-500">Generating QR...</div>
                    )}
                  </div>
                  <p className="mt-3 text-xl font-black text-emerald-100">{formatCurrency(total)}</p>
                </div>
              ) : (
                <div className="rounded-2xl border border-white/15 bg-white/[0.08] p-4 shadow-[0_12px_36px_rgba(2,6,23,0.35)]">
                  <p className="text-xs font-bold uppercase tracking-[0.12em] text-emerald-200">Cash Summary</p>
                  <div className="mt-2 space-y-2 text-sm text-emerald-100/85">
                    <div className="flex items-center justify-between">
                      <span>Received</span>
                      <span className="font-bold text-white">{formatCurrency(amountTendered)}</span>
                    </div>
                    <div className="flex items-center justify-between">
                      <span>Change</span>
                      <span className="font-bold text-emerald-200">{formatCurrency(changeAmount)}</span>
                    </div>
                  </div>
                </div>
              )}

              {displayState.updatedAt && (
                <p className="text-right text-xs text-emerald-100/70">
                  Last update: {new Date(displayState.updatedAt).toLocaleTimeString('en-US')}
                </p>
              )}
            </aside>
          </aside>
        </div>
      </main>
    </div>
  );
};

export default CustomerDisplay;
